// src/TravelHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TravelHistory({ employee }) {
  const navigate = useNavigate();
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/travel-expenses?empld=${encodeURIComponent(
          employee.empld
        )}`
      );
      const data = await res.json();
      setTravelExpenses(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Travel history fetch error:", err);
      setTravelExpenses([]);
    }
  };

  const filteredTravel = travelExpenses.filter((t) => {
    const dateStr = t.travel_date?.split?.("T")?.[0] || t.travel_date;
    if (startDate && dateStr < startDate) return false;
    if (endDate && dateStr > endDate) return false;
    return true;
  });

  const handleDownloadPDF = () => {
    window.print();
  };

  const deleteTravel = async (id) => {
    if (!window.confirm("Delete this travel record?")) return;
    try {
      const res = await fetch(`${apiBase}/travel-expenses/${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success && res.status !== 200) {
        alert(data.message || "Failed to delete travel record");
        return;
      }
      setTravelExpenses((prev) => prev.filter((t) => t.id !== id));
    } catch (err) {
      console.error("Delete travel error:", err);
      alert("Error deleting travel record");
    }
  };

  const editTravel = async (row) => {
    const newDate =
      window.prompt(
        "Travel Date (YYYY-MM-DD):",
        row.travel_date?.split?.("T")?.[0] || row.travel_date
      ) || row.travel_date;
    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;
    const newFrom =
      window.prompt("From:", row.location_from || row.from) ||
      row.location_from ||
      row.from;
    const newTo =
      window.prompt("To:", row.location_to || row.to) ||
      row.location_to ||
      row.to;
    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          travel_date: newDate,
          purpose: newPurpose,
          location_from: newFrom,
          location_to: newTo,
          amount: newAmount,
          mode_of_travel: row.mode_of_travel || "",
        }),
      });
      const data = await res.json();
      if (!data.success && res.status !== 200) {
        alert(data.message || "Failed to update travel record");
        return;
      }

      setTravelExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                travel_date: newDate,
                purpose: newPurpose,
                location_from: newFrom,
                location_to: newTo,
                amount: newAmount,
              }
            : t
        )
      );
    } catch (err) {
      console.error("Update travel error:", err);
      alert("Error updating travel record");
    }
  };

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/history")}
            style={backBtn}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Travel Expense History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Filters (date only) */}
        <div style={filterBar}>
          <div style={filterBlock}>
            <span>From Date</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div style={filterBlock}>
            <span>To Date</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear Filters
          </button>

          <button
            onClick={handleDownloadPDF}
            style={downloadBtn}
          >
            Download PDF
          </button>
        </div>

        {/* Table */}
        <table style={tableStyle}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Amount</th>
              <th>From</th>
              <th>To</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredTravel.map((t) => (
              <tr key={t.id}>
                <td>{t.travel_date?.split?.("T")?.[0] || t.travel_date}</td>
                <td>{t.purpose}</td>
                <td>₹{t.amount}</td>
                <td>{t.location_from || t.from}</td>
                <td>{t.location_to || t.to}</td>
                <td>
                  <button
                    style={actionBtn}
                    onClick={() => editTravel(t)}
                  >
                    Edit
                  </button>
                  <button
                    style={{ ...actionBtn, borderColor: "#c62828", color: "#c62828" }}
                    onClick={() => deleteTravel(t.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
            {filteredTravel.length === 0 && (
              <tr>
                <td colSpan="6" style={{ textAlign: "center", padding: 10 }}>
                  No travel records match your filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const centerScreen = {
  minHeight: "100vh",
  background: lightGreen,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#ffffff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const filterBar = {
  display: "flex",
  flexWrap: "wrap",
  gap: 10,
  alignItems: "center",
  margin: "14px 0",
  background: "#f9fff9",
  borderRadius: 10,
  padding: 10,
  border: "1px solid #eaf8f0",
};

const filterBlock = {
  display: "flex",
  flexDirection: "column",
  fontSize: 12,
};

const filterInput = {
  padding: "4px 6px",
  borderRadius: 6,
  border: "1px solid #ccc",
  fontSize: 12,
};

const clearBtn = {
  padding: "6px 10px",
  borderRadius: 8,
  border: "1px solid #ccc",
  background: "#fff",
  fontSize: 12,
  cursor: "pointer",
};

const downloadBtn = {
  marginLeft: "auto",
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};

const tableStyle = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const actionBtn = {
  padding: "3px 8px",
  marginRight: 6,
  borderRadius: 6,
  border: "1px solid " + green,
  background: "#fff",
  fontSize: 11,
  cursor: "pointer",
  color: green,
};
